@@ -0,0 +1,68 @@
+/**
+ * Notification models and types.
+ *
+ * These types define the core notification domain: what kinds of notifications
+ * exist, what data they carry, and how they are represented after delivery.
+ */
+
+/**
+ * Supported notification channels. Each channel has a corresponding
+ * NotificationAdapter implementation in src/adapters/.
+ */
+export type NotificationChannel = 'email' | 'webhook' | 'in-app';
+
+/**
+ * Classification of notifications by their trigger.
+ * Used by adapters to format messages appropriately per channel.
+ */
+export type NotificationType =
+  | 'order:confirmation'
+  | 'order:status-update'
+  | 'user:welcome'
+  | 'user:profile-updated';
+
+/**
+ * The payload passed to notification adapters for delivery.
+ * Contains everything an adapter needs to send a notification,
+ * independent of the delivery channel.
+ */
+export interface NotificationPayload {
+  /** Unique notification type for formatting/routing decisions. */
+  type: NotificationType;
+  /** The intended recipient identifier (email address, user ID, etc.). */
+  recipient: string;
+  /** Short summary / subject line. */
+  subject: string;
+  /** Full notification body text. */
+  body: string;
+  /** Arbitrary structured data adapters can use for rich formatting. */
+  metadata?: Record<string, unknown>;
+}
+
+/**
+ * Result returned by an adapter after attempting delivery.
+ */
+export interface NotificationResult {
+  /** Whether delivery succeeded. */
+  success: boolean;
+  /** The channel that handled delivery. */
+  channel: NotificationChannel;
+  /** Optional error message when success is false. */
+  error?: string;
+}
+
+/**
+ * A persisted notification record — the canonical representation
+ * of a notification that has been processed by the system.
+ */
+export interface Notification {
+  id: string;
+  type: NotificationType;
+  recipient: string;
+  subject: string;
+  body: string;
+  channel: NotificationChannel;
+  status: 'sent' | 'failed';
+  sentAt: Date;
+  metadata?: Record<string, unknown>;
+}

