 */
export type NotificationChannel = 'email' | 'webhook' | 'in-app';

/**
 * Classification of notifications by their trigger.
 * Used by adapters to format messages appropriately per channel.
 */
export type NotificationType =
  | 'order:confirmation'
  | 'order:status-update'
  | 'user:welcome'
  | 'user:profile-updated';

/**
 * The payload passed to notification adapters for delivery.
 * Contains everything an adapter needs to send a notification,
 * independent of the delivery channel.
 */
export interface NotificationPayload {
  /** Unique notification type for formatting/routing decisions. */
  type: NotificationType;
  /** The intended recipient identifier (email address, user ID, etc.). */
  recipient: string;
  /** Short summary / subject line. */
  subject: string;
  /** Full notification body text. */
  body: string;
  /** Arbitrary structured data adapters can use for rich formatting. */
  metadata?: Record<string, unknown>;
}

/**
 * Result returned by an adapter after attempting delivery.
 */
export interface NotificationResult {
  /** Whether delivery succeeded. */
  success: boolean;
  /** The channel that handled delivery. */
  channel: NotificationChannel;
  /** Optional error message when success is false. */
  error?: string;
}

/**
 * A persisted notification record — the canonical representation
 * of a notification that has been processed by the system.
 */
export interface Notification {
  id: string;
  type: NotificationType;
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  status: 'sent' | 'failed';
  sentAt: Date;
  metadata?: Record<string, unknown>;
}

/**
 * NotificationAdapter — the interface all notification delivery channels must implement.
 *
 * ARCHITECTURAL CONSTRAINT:
 * Every notification channel (email, webhook, in-app, SMS, etc.) must implement
 * this interface. The NotificationService routes payloads to adapters based on
 * channel; it never sends notifications directly.
 *
 * To add a new channel:
 * 1. Create a new adapter file in src/adapters/ (e.g., sms.adapter.ts)
 * 2. Implement the NotificationAdapter interface
 * 3. Register the adapter with NotificationService via registerAdapter()
 *
 * Adapters are responsible for:
 * - Transforming NotificationPayload into channel-specific format
 * - Handling delivery (or stubbing it for development)
 * - Returning a NotificationResult indicating success/failure
 */

import type {
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';

export interface NotificationAdapter {
  /** The channel this adapter handles. Must be unique per adapter. */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this channel.
   * Must not throw — return a failed NotificationResult instead.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs email delivery rather than
 * sending real emails. Replace the send() body with an actual email
 * provider (SendGrid, SES, SMTP, etc.) for production use.
 *
 * Implements NotificationAdapter so it can be registered with
 * NotificationService for the 'email' channel.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: Array<{ to: string; subject: string; body: string; sentAt: Date }> = [];

  /**
   * Send a notification as an email.
   *
   * Stub: logs the email and stores it in memory.
   * Production: replace with real email provider call.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

    this.sentEmails.push({
      to: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      sentAt: new Date(),
    });

    return { success: true, channel: 'email' };
  }

  /**
   * Get all emails sent by this adapter (useful for testing).
   */
  getSentEmails(): Array<{ to: string; subject: string; body: string; sentAt: Date }> {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history (useful for testing).
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

