/**
 * Notification service — the central hub for notification delivery.
 *
 * ARCHITECTURE:
 * This service uses the event-driven pattern exclusively. It subscribes to
 * domain events on the EventBus and routes notifications through registered
 * NotificationAdapter implementations.
 *
 * Flow:
 * 1. A domain service (OrderService, UserService, etc.) emits an event
 *    via EventBus (e.g., 'order:created', 'notification:send').
 * 2. NotificationService listens for these events.
 * 3. For domain events, it constructs a NotificationPayload and routes it
 *    to the appropriate adapter(s).
 * 4. For 'notification:send' events, it delivers the payload directly to
 *    the specified channel adapters.
 * 5. After delivery, it emits a 'notification:sent' event for auditing.
 *
 * CONSTRAINTS:
 * - All notifications must go through EventBus.emit() — no direct calls.
 * - All delivery channels must implement the NotificationAdapter interface.
 * - Register adapters via registerAdapter() before emitting events.
 *
 * Depends on:
 * - EventBus (event system) for all event communication
 * - NotificationAdapter implementations for channel-specific delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  NotificationSendEvent,
} from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a notification adapter for a delivery channel.
   * Each channel can have exactly one adapter.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registering adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to all events that trigger notifications.
   */
  private registerEventHandlers(): void {
    // Domain event: order created — send confirmation to buyer
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    // Domain event: order status changed — notify buyer of update
    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });

    // Generic notification event — allows any service to request a notification
    this.eventBus.on<NotificationSendEvent>('notification:send', (event) => {
      return this.deliverToChannels(event.payload, event.channels);
    });
  }

  /**
   * Handle order created event — send confirmation to user.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    const payload: NotificationPayload = {
      type: 'order:confirmation',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      metadata: { orderId: event.order.id, userId: event.user.id },
    };

    await this.deliverToChannels(payload, ['email']);
  }

  /**
   * Handle order status change — notify user of update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const payload: NotificationPayload = {
      type: 'order:status-update',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      metadata: {
        orderId: event.order.id,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    };

    await this.deliverToChannels(payload, ['email']);
  }

  /**
   * Deliver a notification payload to the specified channels.
   * Falls back to in-memory storage if no adapter is registered for a channel.
   */
  private async deliverToChannels(
    payload: NotificationPayload,
    channels: NotificationChannel[],
  ): Promise<void> {
    for (const channel of channels) {
      const adapter = this.adapters.get(channel);

      if (adapter) {
        const result = await adapter.send(payload);
        const notification: Notification = {
          id: generateNotificationId(),
          type: payload.type,
          recipient: payload.recipient,
          subject: payload.subject,
          body: payload.body,
          channel,
          status: result.success ? 'sent' : 'failed',
          sentAt: new Date(),
          metadata: payload.metadata,
        };
        this.notifications.push(notification);

        await this.eventBus.emit({
          type: 'notification:sent',
          notificationId: notification.id,
          channel,
          success: result.success,
          error: result.error,
          timestamp: new Date(),
        });
      } else {
        // No adapter registered — store as sent for backward compatibility
        this.logger.warn(`No adapter registered for channel: ${channel}, storing in-memory`);
        const notification: Notification = {
          id: generateNotificationId(),
          type: payload.type,
          recipient: payload.recipient,
          subject: payload.subject,
          body: payload.body,
          channel,
          status: 'sent',
          sentAt: new Date(),
          metadata: payload.metadata,
        };
        this.notifications.push(notification);
      }
    }
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

